    public function testXdrClaimAtomTypeEnumRoundTrip(): void
    {
        $values = [XdrClaimAtomType::V0, XdrClaimAtomType::ORDER_BOOK, XdrClaimAtomType::LIQUIDITY_POOL];
        foreach ($values as $v) {
            $original = new XdrClaimAtomType($v);
            $encoded = $original->encode();
            $decoded = XdrClaimAtomType::decode(new XdrBuffer($encoded));
            $this->assertEquals($v, $decoded->getValue(), 'Binary roundtrip failed for value ' . $v);
            $b64Decoded = XdrClaimAtomType::fromBase64Xdr($original->toBase64Xdr());
            $this->assertEquals($v, $b64Decoded->getValue(), 'Base64 roundtrip failed for value ' . $v);
        }
    }

