        $samples[] = (new XdrManageOfferResult(new XdrManageOfferResultCode(XdrManageOfferResultCode::LOW_RESERVE)))->toJsonValue();
        $valid = $samples[0];
        foreach ($samples as $s) { if (!is_string($s)) { $valid = $s; break; } }
